3611	\begin{lemma}[Basic opens form a topological basis of the prime spectrum]
3612	  \label{lem:primeSpectrum_isBasis_basicOpen}
3613	  \lean{PrimeSpectrum.isTopologicalBasis_basic_opens}
3614	  \mathlibok
3615	  \textit{Provided by Mathlib.}
3616	  For a commutative (semi)ring \(R\), the distinguished/basic opens \(D(r)\), \(r \in R\), form a
3617	  topological basis of \(\operatorname{Spec} R\): the sets \(\{D(r) : r \in R\}\) are open and every
3618	  open of \(\operatorname{Spec} R\) is a union of them. This is the basis input used to refine an
3619	  arbitrary open covering of a distinguished open to one by basic opens
3620	  (Lemma~\ref{lem:standard_cover_cofinal}).
3621	\end{lemma}
